import{_ as e,o as a,c as r,ag as n}from"./chunks/framework.eQLvDOR_.js";const d=JSON.parse('{"title":"编排器与子 Agent 模式 (Orchestrator-Subagent Pattern)","description":"","frontmatter":{},"headers":[],"relativePath":"wiki/concepts/orchestrator-subagent-pattern.md","filePath":"wiki/concepts/orchestrator-subagent-pattern.md","lastUpdated":null}'),o={name:"wiki/concepts/orchestrator-subagent-pattern.md"};function i(l,t,s,c,h,g){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="编排器与子-agent-模式-orchestrator-subagent-pattern" tabindex="-1">编排器与子 Agent 模式 (Orchestrator-Subagent Pattern) <a class="header-anchor" href="#编排器与子-agent-模式-orchestrator-subagent-pattern" aria-label="Permalink to &quot;编排器与子 Agent 模式 (Orchestrator-Subagent Pattern)&quot;">​</a></h1><h2 id="核心定义" tabindex="-1">核心定义 <a class="header-anchor" href="#核心定义" aria-label="Permalink to &quot;核心定义&quot;">​</a></h2><p>一种将复杂任务拆解并分发给专业子 Agent 处理的多体架构模式。主编排器 (Orchestrator) 负责理解用户意图、规划步骤并分派任务，而子 Agent (Subagent) 负责在特定领域内执行任务并返回结果。</p><h2 id="与单一-agent-的区别" tabindex="-1">与单一 Agent 的区别 <a class="header-anchor" href="#与单一-agent-的区别" aria-label="Permalink to &quot;与单一 Agent 的区别&quot;">​</a></h2><ul><li><strong>状态解耦</strong>: 编排器不需要保留子 Agent 执行时的详尽局部状态，只关心输入输出，降低了上下文溢出风险。</li><li><strong>专职专能</strong>: 子 Agent 可以配备不同的系统指令 (System Prompt) 和工具集，甚至使用较小、更快、更便宜的模型。</li><li><strong>并行执行</strong>: 对于互不依赖的子任务，编排器可以同时唤起多个子 Agent，极大缩短执行时间。</li></ul><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><ul><li>复杂代码重构。</li><li>多步骤的深度研究 (Deep Research)。</li><li>需要多源数据合并的分析任务。</li></ul><h2 id="关联概念" tabindex="-1">关联概念 <a class="header-anchor" href="#关联概念" aria-label="Permalink to &quot;关联概念&quot;">​</a></h2><ul><li>[[multi-agent-orchestrator]]</li><li>[[hermes-agent-framework]]</li><li>[[durable-agent-primitives]]</li></ul>',9)])])}const p=e(o,[["render",i]]);export{d as __pageData,p as default};
